# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict, Counter
import numpy as np
import pickle
from sklearn.ensemble import RandomForestClassifier
from sklearn.preprocessing import LabelEncoder
import os

app = Flask(__name__)

# Store labels from annotators
labels_db = defaultdict(list)
model = None
label_encoder = LabelEncoder()

@app.route('/label', methods=['POST'])
def add_label():
    data = request.get_json()
    image_id = data['image_id']
    label = data['label']
    annotator_id = data['annotator_id']
    
    labels_db[image_id].append({
        'label': label,
        'annotator_id': annotator_id
    })
    
    return jsonify({"status": "success"})

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated = {}
    for image_id, labels in labels_db.items():
        # Majority voting
        label_counts = Counter([l['label'] for l in labels])
        majority_label = label_counts.most_common(1)[0][0]
        aggregated[image_id] = majority_label
    
    return jsonify(aggregated)

@app.route('/train', methods=['POST'])
def train_model():
    global model, label_encoder
    
    # Get all labeled data
    all_data = []
    all_labels = []
    
    for image_id, labels in labels_db.items():
        # Use majority vote for each image
        label_counts = Counter([l['label'] for l in labels])
        majority_label = label_counts.most_common(1)[0][0]
        all_labels.append(majority_label)
        
        # For simplicity, we'll use a dummy feature vector
        # In practice, you'd extract actual image features
        all_data.append([hash(image_id) % 1000])  # Dummy features
    
    if len(all_data) == 0:
        return jsonify({"status": "no data to train"})
    
    # Encode labels
    encoded_labels = label_encoder.fit_transform(all_labels)
    
    # Train model
    model = RandomForestClassifier(n_estimators=100, random_state=42)
    model.fit(all_data, encoded_labels)
    
    return jsonify({"status": "model trained", "samples": len(all_data)})

@app.route('/predict', methods=['POST'])
def predict():
    if model is None:
        return jsonify({"error": "Model not trained"}), 400
    
    data = request.get_json()
    image_id = data['image_id']
    
    # Dummy feature extraction
    features = [[hash(image_id) % 1000]]
    
    prediction = model.predict(features)
    predicted_label = label_encoder.inverse_transform(prediction)[0]
    
    return jsonify({"image_id": image_id, "predicted_label": predicted_label})

@app.route('/status', methods=['GET'])
def status():
    return jsonify({
        "total_images": len(labels_db),
        "total_labels": sum(len(labels) for labels in labels_db.values()),
        "model_trained": model is not None
    })

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)